section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "title": "ai-status-digest-pipeline-output",
  "required": [
    "artefact_id",
    "owner",
    "decision",
    "rationale",
    "inputs_used",
    "version",
    "last_reviewed",
    "forbidden_seen"
  ],
  "properties": {
    "artefact_id": {
      "description": "Stable slug used to reference this artefact downstream.",
      "type": "string"
    },
    "owner": {
      "description": "Single named accountable owner (handle / email / role).",
      "type": "string"
    },
    "decision": {
      "description": "The chosen value, ranking, or verdict produced by this run.",
      "type": "string"
    },
    "rationale": {
      "description": "\u22652 sentences citing at least one input artefact by name.",
      "type": "string"
    },
    "inputs_used": {
      "description": "List of input artefact names with source paths or URLs.",
      "type": "array"
    },
    "version": {
      "description": "Semver, e.g. 1.0.0.",
      "type": "string"
    },
    "last_reviewed": {
      "description": "ISO-8601 date the artefact was last validated.",
      "type": "string"
    },
    "forbidden_seen": {
      "description": "Forbidden patterns matched (must be empty).",
      "type": "array"
    }
  }
}
